import{_ as e,p as a,q as s,a1 as n}from"./framework-5866ffd3.js";const i={},t=n(`<h1 id="tempfile" tabindex="-1"><a class="header-anchor" href="#tempfile" aria-hidden="true">#</a> tempfile</h1><p>shell中给临时文件命名</p><h2 id="补充说明" tabindex="-1"><a class="header-anchor" href="#补充说明" aria-hidden="true">#</a> 补充说明</h2><p>有时候在写Shell脚本的时候需要一些临时存储数据的才做，最适合存储临时文件数据的位置就是<code>/tmp</code>，因为该目录中所有的内容在系统重启后就会被清空。下面是两种方法为临时数据生成标准的文件名。</p><h3 id="tempfile命令" tabindex="-1"><a class="header-anchor" href="#tempfile命令" aria-hidden="true">#</a> tempfile命令</h3><p><code>tempfile命令</code>只有在基于Debian的发行版中才默认自带，比如Ubuntu，其他发行版没有这个命令。</p><p>用tempfile命令为一个临时文件命名：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token assign-left variable">temp_file_name</span><span class="token operator">=</span><span class="token variable"><span class="token variable">$(</span>tempfile<span class="token variable">)</span></span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>用一个加带了随机数的文件名作为临时文件命名：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token assign-left variable">temp_file_name</span><span class="token operator">=</span><span class="token string">&quot;/tmp/file_<span class="token environment constant">$RANDOM</span>&quot;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>$RANDOM是一个返回随机数的环境变量。</p><h3 id="变量" tabindex="-1"><a class="header-anchor" href="#变量" aria-hidden="true">#</a> $$变量</h3><p>如果没有tempfile命令的Linux发行版，也可以使用自己的临时文件名：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token assign-left variable">temp_file_name</span><span class="token operator">=</span><span class="token string">&quot;/tmp/file.$&quot;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><code>$$</code>是系统预定义变量，显示当前所在进程的进程号，用<code>.$$</code>作为添加的后缀会被扩展成当前运行脚本的进程id。</p>`,15),l=[t];function d(p,r){return a(),s("div",null,l)}const o=e(i,[["render",d],["__file","tempfile.html.vue"]]);export{o as default};
